    },
    "provenance-string" : "0oRRowNjeG1sBGdlYzIua2V5ASag9lhASSZbjoYsJr+BhT29AKyyhRy98u8zlONkIJSdnvhQqz3x6DlI7yuXMduwu1X2dkBVeeIloLwvjWUlW+BSvaVWlA=="
